namespace Payments;

public interface IPaymentProvider
{
    Task<ChargeResult> CreateChargeAsync(string cardToken, decimal amount);
    Task<RefundResult> CreateRefundAsync(string chargeId);
}

public sealed class PaymentGateway
{
    private readonly IPaymentProvider _provider;

    public PaymentGateway(IPaymentProvider provider)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));
    }

    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token is required.", nameof(cardToken));
        if (amount <= 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount must be positive.");
        if (amount > 999_999.99m)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount exceeds maximum allowed.");

        return await _provider.CreateChargeAsync(cardToken, amount);
    }

    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID is required.", nameof(chargeId));

        return await _provider.CreateRefundAsync(chargeId);
    }

    public Task<WebhookResult> ProcessWebhookAsync(string eventType, string payload)
    {
        if (string.IsNullOrWhiteSpace(eventType))
            throw new ArgumentException("Event type is required.", nameof(eventType));
        if (string.IsNullOrWhiteSpace(payload))
            throw new ArgumentException("Payload is required.", nameof(payload));

        var status = eventType switch
        {
            "charge.succeeded" or "charge.failed" => WebhookStatus.Processed,
            "refund.succeeded" or "refund.failed" => WebhookStatus.Processed,
            _ => WebhookStatus.Ignored,
        };

        return Task.FromResult(new WebhookResult(eventType, status));
    }
}

public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);
public record WebhookResult(string EventType, WebhookStatus Status);

public enum WebhookStatus
{
    Processed,
    Ignored
}

