using Moq;
using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public class PaymentGatewayConstructorTests
{
    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new Payments.PaymentGateway(null!));
    }

    [TestMethod]
    public void Constructor_ValidProvider_CreatesInstance()
    {
        var provider = new Mock<IPaymentProvider>();
        var gateway = new Payments.PaymentGateway(provider.Object);
        Assert.IsNotNull(gateway);
    }
}

[TestClass]
public class ChargeAsyncTests
{
    private Mock<IPaymentProvider> _providerMock = null!;
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _providerMock = new Mock<IPaymentProvider>();
        _gateway = new Payments.PaymentGateway(_providerMock.Object);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ReturnsSuccessResult()
    {
        var expected = new ChargeResult("ch_123", true);
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_visa", 49.99m))
            .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_visa", 49.99m);

        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderReturnsFailure_ReturnsFailureResult()
    {
        var expected = new ChargeResult("ch_456", false);
        _providerMock
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_declined", 100m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidInput_PassesArgumentsToProvider()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_test", 25.50m))
            .ReturnsAsync(new ChargeResult("ch_1", true));

        await _gateway.ChargeAsync("tok_test", 25.50m);

        _providerMock.Verify(p => p.CreateChargeAsync("tok_test", 25.50m), Times.Once);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_InvalidToken_DoesNotCallProvider()
    {
        try { await _gateway.ChargeAsync("", 10m); } catch { }

        _providerMock.Verify(
            p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()), Times.Never);
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100.50)]
    public async Task ChargeAsync_NonPositiveAmount_ThrowsArgumentOutOfRange(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_visa", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountExceedsMaximum_ThrowsArgumentOutOfRange()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_visa", 1_000_000m));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountAtMaximum_Succeeds()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), 999_999.99m))
            .ReturnsAsync(new ChargeResult("ch_max", true));

        var result = await _gateway.ChargeAsync("tok_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallestValidAmount_Succeeds()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), 0.01m))
            .ReturnsAsync(new ChargeResult("ch_penny", true));

        var result = await _gateway.ChargeAsync("tok_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ThrowsAsync(new InvalidOperationException("Network error"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.ChargeAsync("tok_visa", 10m));
    }
}

[TestClass]
public class RefundAsyncTests
{
    private Mock<IPaymentProvider> _providerMock = null!;
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
